  "تربية الطير": "تَرْبِيَةُ الطَّيْرِ",
  "من هو مؤلف الأصول الثلاثة": "مَنْ هُوَ مُؤَلِّفُ الْأُصُولِ الثَّلَاثَةِ؟",
  "مؤلف الأصول الثلاثة هو الشيخ محمد بن عبد الوهاب رحمه الله وكتابه يشرح أسئلة القبر الثلاثة": "مُؤَلِّفُ الْأُصُولِ الثَّلَاثَةِ هُوَ الشَّيْخُ مُحَمَّدُ بْنُ عَبْدِ الْوَهَّابِ رَحِمَهُ اللَّهُ، وَكِتَابُهُ يَشْرَحُ أَسْئِلَةَ الْقَبْرِ الثَّلَاثَةَ.",
  "محمد بن عبد الوهاب": "مُحَمَّدُ بْنُ عَبْدِ الْوَهَّابِ",
  "ابن تيمية": "ابْنُ تَيْمِيَّةَ",
  "ابن القيم": "ابْنُ الْقَيِّمِ",
  "البخاري": "الْبُخَارِيُّ",
  "أين ولد المؤلف": "أَيْنَ وُلِدَ الْمُؤَلِّفُ؟",
  "ولد الشيخ محمد بن عبد الوهاب في العيينة بنجد ثم قام بالدعوة إلى التوحيد": "وُلِدَ الشَّيْخُ مُحَمَّدُ بْنُ عَبْدِ الْوَهَّابِ فِي الْعُيَيْنَةِ بِنَجْدٍ، ثُمَّ قَامَ بِالدَّعْوَةِ إِلَى التَّوْحِيدِ.",
  "العيينة": "الْعُيَيْنَةُ",
  "المدينة": "الْمَدِينَةُ",
