  "أسئلة القبر الثلاثة من ربك وما دينك ومن نبيك": "أَسْئِلَةُ الْقَبْرِ الثَّلَاثَةُ: مَنْ رَبُّكَ؟ وَمَا دِينُكَ؟ وَمَنْ نَبِيُّكَ؟",
  "من ربك ما دينك من نبيك": "مَنْ رَبُّكَ؟ مَا دِينُكَ؟ مَنْ نَبِيُّكَ؟",
  "ما اسمك كم عمرك أين تسكن": "مَا اسْمُكَ؟ كَمْ عُمْرُكَ؟ أَيْنَ تَسْكُنُ؟",
  "ماذا تعمل ماذا تأكل ماذا تشرب": "مَاذَا تَعْمَلُ؟ مَاذَا تَأْكُلُ؟ مَاذَا تَشْرَبُ؟",
  "من أبوك من أمك من أخوك": "مَنْ أَبُوكَ؟ مَنْ أُمُّكَ؟ مَنْ أَخُوكَ؟",
  "من ربك وما دينك ومن نبيك": "مَنْ رَبُّكَ؟ وَمَا دِينُكَ؟ وَمَنْ نَبِيُّكَ؟",
  "المسائل الأربع العلم والعمل به والدعوة إليه والصبر على الأذى فيه": "الْمَسَائِلُ الْأَرْبَعُ: الْعِلْمُ، وَالْعَمَلُ بِهِ، وَالدَّعْوَةُ إِلَيْهِ، وَالصَّبْرُ عَلَى الْأَذَى فِيهِ.",
  "العلم والعمل والدعوة والصبر": "الْعِلْمُ وَالْعَمَلُ وَالدَّعْوَةُ وَالصَّبْرُ",
  "الصلاة والزكاة والصيام والحج": "الصَّلَاةُ وَالزَّكَاةُ وَالصِّيَامُ وَالْحَجُّ",
  "العلم والمال والجاه والصحة": "الْعِلْمُ وَالْمَالُ وَالْجَاهُ وَالصِّحَّةُ",
  "الأكل والشرب والنوم والراحة": "الْأَكْلُ وَالشُّرْبُ وَالنَّوْمُ وَالرَّاحَةُ",
  "ما الدليل على أن العلم قبل العمل": "مَا الدَّلِيلُ عَلَى أَنَّ الْعِلْمَ قَبْلَ الْعَمَلِ؟",
  "الدليل أن العلم قبل العمل قوله تعالى ﴿فاعلم أنه لا إله إلا الله﴾ فقدم العلم على العمل": "الدَّلِيلُ أَنَّ الْعِلْمَ قَبْلَ الْعَمَلِ قَوْلُهُ تَعَالَى: ﴿فَاعْلَمْ أَنَّهُ لَا إِلَهَ إِلَّا اللَّهُ﴾؛ فَقَدَّمَ الْعِلْمَ عَلَى الْعَمَلِ.",
  "قوله فاعلم أنه لا إله إلا الله": "قَوْلُهُ: فَاعْلَمْ أَنَّهُ لَا إِلَهَ إِلَّا اللَّهُ",
  "قوله وأقيموا الصلاة": "قَوْلُهُ: وَأَقِيمُوا الصَّلَاةَ",
  "قوله وآتوا الزكاة": "قَوْلُهُ: وَآتُوا الزَّكَاةَ",
  "قوله يا أيها الذين آمنوا": "قَوْلُهُ: يَا أَيُّهَا الَّذِينَ آمَنُوا",
  "إذا قيل لك من ربك فماذا تقول": "إِذَا قِيلَ لَكَ: مَنْ رَبُّكَ؟ فَمَاذَا تَقُولُ؟",
  "إذا قيل من ربك فقل ربي الله الذي رباني بنعمه وهو المستحق للعبادة وحده": "إِذَا قِيلَ: مَنْ رَبُّكَ؟ فَقُلْ: رَبِّيَ اللَّهُ الَّذِي رَبَّانِي بِنِعَمِهِ، وَهُوَ الْمُسْتَحِقُّ لِلْعِبَادَةِ وَحْدَهُ.",
  "ربي الله الذي رباني": "رَبِّيَ اللَّهُ الَّذِي رَبَّانِي",
