  "بالسؤال فقط": "بِالسُّؤَالِ فَقَطْ",
  "بالتخمين": "بِالتَّخْمِينِ",
  "ماذا تعرف عن مؤلف الكتاب": "مَاذَا تَعْرِفُ عَنْ مُؤَلِّفِ الْكِتَابِ",
  "ما معنى العالم": "مَا مَعْنَى (الْعَالَمِ)؟",
  "العالم كل ما سوى الله من المخلوقات والله وحده الخالق لكل شيء": "الْعَالَمُ: كُلُّ مَا سِوَى اللَّهِ مِنَ الْمَخْلُوقَاتِ؛ وَاللَّهُ وَحْدَهُ الْخَالِقُ لِكُلِّ شَيْءٍ.",
  "كل ما سوى الله": "كُلُّ مَا سِوَى اللَّهِ",
  "البشر فقط": "الْبَشَرُ فَقَطْ",
  "الأرض فقط": "الْأَرْضُ فَقَطْ",
  "السماء فقط": "السَّمَاءُ فَقَطْ",
  "الرب هو الخالق لهذه الأشياء وهو المستحق للعبادة": "الرَّبُّ هُوَ الْخَالِقُ لِهَذِهِ الْأَشْيَاءِ وَهُوَ الْمُسْتَحِقُّ لِلْعِبَادَةِ.",
  "صحيح الرب هو الخالق المدبر وهو وحده المستحق للعبادة فتوحيد الربوبية يقتضي توحيد الألوهية": "صَحِيحٌ: الرَّبُّ هُوَ الْخَالِقُ الْمُدَبِّرُ، وَهُوَ وَحْدَهُ الْمُسْتَحِقُّ لِلْعِبَادَةِ؛ فَتَوْحِيدُ الرُّبُوبِيَّةِ يَقْتَضِي تَوْحِيدَ الْأُلُوهِيَّةِ.",
  "العبادة اسم جامع لكل ما يحبه الله ويرضاه من الأقوال والأعمال الظاهرة والباطنة": "الْعِبَادَةُ اسْمٌ جَامِعٌ لِكُلِّ مَا يُحِبُّهُ اللَّهُ وَيَرْضَاهُ مِنَ الْأَقْوَالِ وَالْأَعْمَالِ الظَّاهِرَةِ وَالْبَاطِنَةِ.",
  "اسم جامع لكل ما يحبه الله ويرضاه من الأقوال والأعمال": "اسْمٌ جَامِعٌ لِكُلِّ مَا يُحِبُّهُ اللَّهُ وَيَرْضَاهُ مِنَ الْأَقْوَالِ وَالْأَعْمَالِ",
  "الذكر فقط": "الذِّكْرُ فَقَطْ",
  "هل يرضى الله أن يشرك معه أحد في عبادته": "هَلْ يَرْضَى اللَّهُ أَنْ يُشْرِكَ مَعَهُ أَحَدٌ فِي عِبَادَتِهِ؟",
  "لا يرضى الله أن يشرك معه أحد في عبادته فالشرك ظلم عظيم لا يغفر لمن مات عليه": "لَا يَرْضَى اللَّهُ أَنْ يُشْرِكَ مَعَهُ أَحَدٌ فِي عِبَادَتِهِ؛ فَالشِّرْكُ ظُلْمٌ عَظِيمٌ لَا يُغْفَرُ لِمَنْ مَاتَ عَلَيْهِ.",
  "لا يرضى الله أن يشرك معه أحد": "لَا يَرْضَى اللَّهُ أَنْ يُشْرِكَ مَعَهُ أَحَدٌ",
  "لا لا يرضى": "لَا، لَا يَرْضَى",
  "نعم يرضى": "نَعَمْ، يَرْضَى",
