  "أعظم الذنوب على الإطلاق هو": "أَعْظَمُ الذُّنُوبِ عَلَى الْإِطْلَاقِ هُوَ:",
  "الرقى والتمائم والتولة حكمها في الحديث": "الرُّقَى وَالتَّمَائِمُ وَالتِّوَلَةُ» حُكْمُهَا فِي الْحَدِيثِ:",
  "مكروهة": "مَكْرُوهَةٌ",
  "الحكم الصحيح هو شرك كما قرره النص الشرعي في الباب": "الْحُكْمُ الصَّحِيحُ هُوَ «شِرْكٌ»، كَمَا قَرَّرَهُ النَّصُّ الشَّرْعِيُّ فِي الْبَابِ.",
  "قال النبي ﷺ لصاحب حلقة الصفر انزعها فإنها لا تزيدك إلا": "قَالَ النَّبِيُّ ﷺ لِصَاحِبِ حَلْقَةِ الصُّفْرِ: «انْزِعْهَا فَإِنَّهَا لَا تَزِيدُكَ إِلَّا»:",
